        {/* System Settings & Actions */}
        <div className="p-4 border-t border-slate-800 space-y-3">
          <button
            onClick={handleClearData}
            className="w-full flex items-center justify-center px-4 py-2 bg-red-500/10 text-red-400 hover:bg-red-500/20 rounded-lg text-sm font-medium transition-colors border border-red-500/20"
          >
            <Trash2 className="w-4 h-4 mr-2" />
