  const [alertMessage, setAlertMessage] = useState<string | null>(null);

  const basePath = `/HORECA/COSTCONTROL/${restaurantId}`;

  const navItems = [
    { path: `${basePath}/dashboard`, label: t(language, 'dashboard'), icon: LayoutDashboard },
