import React, { useMemo } from 'react';
import { useAppStore } from '../store';
import { t } from '../i18n';
import { BrainCircuit, LineChart as LineChartIcon, ShieldAlert, AlertCircle, PackageOpen, CheckCircle } from 'lucide-react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend } from 'recharts';

export const AiAnalyticsPage: React.FC = () => {
  const { language, products, purchases, sales, dishes } = useAppStore();

  // Color palette for the multi-line chart
  const CHART_COLORS = ['#3b82f6', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6'];

  // --- Logic for Price Trends (Chart) ---
  const priceChartDataAndLines = useMemo(() => {
    // 1. Identify Top 5 Products by total purchase spend
    const topProducts = products
      .map(p => {
        const totalSpend = purchases
          .filter(pur => pur.productId === p.id)
          .reduce((sum, pur) => sum + pur.total, 0);
        return { ...p, totalSpend };
      })
      .filter(p => p.totalSpend > 0)
      .sort((a, b) => b.totalSpend - a.totalSpend)
      .slice(0, 5);

    if (topProducts.length === 0) return { data: [], lines: [] };

    // 2. Get unique, sorted dates from purchases
    const sortedDates = [...new Set(purchases.map(p => p.date))].sort();

    // 3. Map dates to data points
    const data = sortedDates.map(date => {
      const point: any = { date };
      topProducts.forEach(tp => {
        // Find if product was purchased on this date
        // If there are multiple purchases on same date, take the average or just the latest. Let's take the first found for simplicity
        const pur = purchases.find(p => p.productId === tp.id && p.date === date);
        if (pur) {
          point[tp.name] = pur.price;
        }
      });
      return point;
    });

    return { data, lines: topProducts.map(tp => tp.name) };
  }, [products, purchases]);

  // --- Logic for Audits & Anomalies ---
  const anomalies = useMemo(() => {
    const alerts: Array<{ id: string; type: 'warning' | 'critical'; title: string; desc: string; icon: any }> = [];

    // Rule 1: Sudden Price Jumps (>15%)
    products.forEach(p => {
      const pPurchases = purchases
        .filter(pur => pur.productId === p.id)
        .sort((a, b) => new Date(a.date).getTime() - new Date(b.date).getTime());

      if (pPurchases.length >= 2) {
        const lastPrice = pPurchases[pPurchases.length - 1].price;
        const prevPrice = pPurchases[pPurchases.length - 2].price;

        if (prevPrice > 0 && lastPrice > prevPrice * 1.15) {
          const percentIncrease = (((lastPrice - prevPrice) / prevPrice) * 100).toFixed(1);
          alerts.push({
            id: `jump-${p.id}`,
            type: 'critical',
            title: `${p.name} - ${t(language, 'priceJumpTitle')}`,
            desc: t(language, 'priceJumpDesc', { percent: percentIncrease, prev: prevPrice.toFixed(2), curr: lastPrice.toFixed(2) }),
            icon: AlertCircle
          });
        }
      }
    });

    // Rule 2: Dead Stock Identification
    // Logic: Product has current stock > 0, but no recorded sales using it.
    const getGrossQuantity = (netQuantity: number, lossPercentage: number = 0): number => {
      const validLoss = Math.min(Math.max(lossPercentage, 0), 99);
      return netQuantity / (1 - (validLoss / 100));
    };

    const balances: Record<string, number> = {};
    products.forEach(p => balances[p.id] = 0);
    purchases.forEach(p => { balances[p.productId] += p.quantity; });

    // Deduct sales
    const consumedMap: Record<string, number> = {};
    sales.forEach(s => {
      const dish = dishes.find(d => d.id === s.dishId);
      if (dish) {
        dish.ingredients.forEach(ing => {
          const grossQty = getGrossQuantity(ing.quantity, ing.lossPercentage || 0);
          balances[ing.productId] -= (grossQty * s.quantity);
          consumedMap[ing.productId] = (consumedMap[ing.productId] || 0) + (grossQty * s.quantity);
        });
      }
    });

    products.forEach(p => {
      const currentStock = balances[p.id] || 0;
      const totalConsumed = consumedMap[p.id] || 0;

      // If we have stock > 5 (arbitrary threshold to ignore tiny leftovers) and 0 consumption
      if (currentStock >= 5 && totalConsumed === 0) {
        alerts.push({
          id: `dead-${p.id}`,
          type: 'warning',
          title: `${p.name} - ${t(language, 'deadStockTitle')}`,
          desc: t(language, 'deadStockDesc', { qty: currentStock.toFixed(2) }),
          icon: PackageOpen
        });
      }
    });

    return alerts;
  }, [products, purchases, sales, dishes, language]);

  return (
    <div className="p-4 sm:p-6 max-w-7xl mx-auto w-full space-y-6">
      <div className="flex items-center space-x-3 mb-6">
        <div className="bg-indigo-100 p-2.5 rounded-xl">
          <BrainCircuit className="w-6 h-6 text-indigo-600" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-900 tracking-tight">{t(language, 'aiInsights')}</h2>
