import { Navigate, useNavigate } from 'react-router-dom';
import { useAppStore } from '../store';
import { t } from '../i18n';
import { Lock, ArrowRight, AlertCircle, ChefHat } from 'lucide-react';

export const LoginPage: React.FC = () => {
  const { language, login, isAuthenticated } = useAppStore();
  const navigate = useNavigate();

  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // If already authenticated, redirect to the app
  if (isAuthenticated) {
    return <Navigate to="/HORECA/COSTCONTROL/123456789/dashboard" replace />;
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const success = login(password);
    if (success) {
      navigate('/HORECA/COSTCONTROL/123456789/dashboard', { replace: true });
    } else {
      setError(t(language, 'invalidPassword'));
      setPassword('');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="max-w-md w-full">
        {/* Logo / Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-brand-600 text-white shadow-lg shadow-brand-500/30 mb-4">
            <ChefHat className="w-8 h-8" />
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight mb-2">
            {t(language, 'appTitle')}
          </h1>
          <p className="text-slate-500 font-medium">
            {t(language, 'loginSubtitle')}
          </p>
        </div>

        {/* Login Card */}
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8">
          <form onSubmit={handleSubmit} className="space-y-6">

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">
                {t(language, 'enterPassword')}
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <Lock className="w-5 h-5 text-slate-400" />
                </div>
                <input
                  type="password"
                  required
                  autoFocus
                  value={password}
                  onChange={(e) => {
                    setPassword(e.target.value);
                    setError('');
                  }}
                  className={`w-full pl-12 pr-4 py-3.5 bg-slate-50 border rounded-xl text-slate-900 font-medium transition-all outline-none focus:ring-2 focus:ring-brand-500 focus:bg-white ${
                    error ? 'border-red-300 focus:ring-red-500' : 'border-slate-200'
                  }`}
                  placeholder="••••••"
                />
              </div>
              {error && (
                <div className="flex items-center mt-3 text-red-600 text-sm font-medium animate-in fade-in slide-in-from-top-1">
                  <AlertCircle className="w-4 h-4 mr-1.5 shrink-0" />
                  {error}
                </div>
              )}
            </div>

            <button
              type="submit"
              className="w-full flex justify-center items-center px-4 py-3.5 bg-brand-600 text-white rounded-xl text-base font-bold hover:bg-brand-700 transition-all shadow-md hover:shadow-lg active:scale-[0.98] group"
            >
              {t(language, 'loginButton')}
              <ArrowRight className="w-5 h-5 ml-2 opacity-70 group-hover:opacity-100 group-hover:translate-x-1 transition-all" />
            </button>

          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Routes, Route, Navigate, Outlet, useParams, useLocation } from 'react-router-dom';
import { useAppStore } from './store';
import { Sidebar } from './components/Sidebar';
import { Header } from './components/Header';
import { LoginPage } from './pages/LoginPage';
import { ProductsPage } from './pages/ProductsPage';
import { PurchasesPage } from './pages/PurchasesPage';
import { DashboardPage } from './pages/DashboardPage';
import { SalesPage } from './pages/SalesPage';
import { InventoryPage } from './pages/InventoryPage';
import { MenuPage } from './pages/MenuPage';
import { SettingsPage } from './pages/SettingsPage';
import { InstructionsPage } from './pages/InstructionsPage';
import { AiAnalyticsPage } from './pages/AiAnalyticsPage';

// Auth Guard Component
const RequireAuth: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const isAuthenticated = useAppStore(state => state.isAuthenticated);
  const location = useLocation();

  if (!isAuthenticated) {
    // Redirect them to the /login page, but save the current location they were trying to go to
    return <Navigate to="/login" state={{ from: location }} replace />;
  }

  return <>{children}</>;
};

// Layout wrapper component
const AppLayout: React.FC = () => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const { restaurantId } = useParams<{ restaurantId: string }>();

  // Strict validation: ID must be exactly 9 or 11 digits
  const isValidId = restaurantId && /^(\d{9}|\d{11})$/.test(restaurantId);

  if (!isValidId) {
    // Redirect to a default valid 9-digit ID if the current one is invalid
    return <Navigate to="/HORECA/COSTCONTROL/123456789/dashboard" replace />;
  }

  return (
    <div className="flex h-screen w-full bg-gray-50 overflow-hidden">
      <Sidebar isOpen={isSidebarOpen} setIsOpen={setIsSidebarOpen} />
      <div className="flex flex-col flex-1 min-w-0 overflow-hidden">
        <Header onMenuClick={() => setIsSidebarOpen(true)} />
        <main className="flex-1 overflow-y-auto overflow-x-hidden relative">
          <Outlet />
        </main>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <Routes>
      {/* Public Route */}
      <Route path="/login" element={<LoginPage />} />

      {/* Main route pattern requiring an ID, protected by RequireAuth */}
      <Route 
        path="/HORECA/COSTCONTROL/:restaurantId" 
        element={
          <RequireAuth>
            <AppLayout />
          </RequireAuth>
        }
      >
        <Route index element={<Navigate to="dashboard" replace />} />
        <Route path="dashboard" element={<DashboardPage />} />
        <Route path="products" element={<ProductsPage />} />
        <Route path="purchases" element={<PurchasesPage />} />
        <Route path="menu" element={<MenuPage />} />
        <Route path="sales" element={<SalesPage />} />
        <Route path="inventory" element={<InventoryPage />} />
        <Route path="settings" element={<SettingsPage />} />
        <Route path="instructions" element={<InstructionsPage />} />
        <Route path="ai-analytics" element={<AiAnalyticsPage />} />
      </Route>

      {/* Catch-all - Redirects to the protected dashboard, which will then redirect to login if not authenticated */}
      <Route path="*" element={<Navigate to="/HORECA/COSTCONTROL/123456789/dashboard" replace />} />
    </Routes>
  );
};

export default App;

