import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { Product, Purchase, Sale, Dish, Language, InventoryAudit, Ingredient, ActivityLog } from './types';

interface AppState {
  language: Language;
  username: string;
  password: string;
  isAuthenticated: boolean;
  isFirstLogin: boolean;
  products: Product[];
  purchases: Purchase[];
  sales: Sale[];
  dishes: Dish[];
  inventoryAudits: InventoryAudit[];
  activityLogs: ActivityLog[];
  setLanguage: (lang: Language) => void;
  login: (inputPassword: string) => boolean;
  changePassword: (newPassword: string) => void;
  updatePassword: (current: string, newPass: string) => boolean;
  addLog: (action: string, details: string) => void;
  clearLogs: () => void;
  updateProductMinBalance: (id: string, minBalance: number) => void;
  addPurchase: (purchase: Omit<Purchase, 'id' | 'total' | 'productId'> & { productName: string, unit: string, category: string, code?: string }) => void;
  editPurchase: (id: string, purchase: Omit<Purchase, 'id' | 'total' | 'productId'> & { productName: string, unit: string, category: string, code?: string }) => void;
  bulkAddPurchases: (purchases: Array<Omit<Purchase, 'id' | 'total' | 'productId'> & { productName: string, unit: string, category: string, code?: string }>) => void;
  deletePurchase: (id: string) => void;
  addSale: (sale: Omit<Sale, 'id' | 'totalRevenue'>) => void;
  editSale: (id: string, sale: Omit<Sale, 'id' | 'totalRevenue'>) => void;
  deleteSale: (id: string) => void;
  addProduct: (product: Product) => void;
  addDish: (dish: Dish) => void;
  editDish: (id: string, dish: Dish) => void;
  deleteDish: (id: string) => void;
  saveInventoryAudit: (audit: Omit<InventoryAudit, 'id'>) => void;
  clearAllData: () => void;
  executeChefsGrandOpeningTest: () => void;
}

const generateId = () => Math.random().toString(36).substring(2, 11);

// Standard Yield Formula: Net Quantity / (1 - LossPercentage / 100)
const getGrossQuantity = (netQuantity: number, lossPercentage: number = 0): number => {
  const validLoss = Math.min(Math.max(lossPercentage, 0), 99); // Prevent division by zero
  return netQuantity / (1 - (validLoss / 100));
};

export const useAppStore = create<AppState>()(
  persist(
    (set, get) => ({
      language: 'ka',
      username: 'Administrator',
      password: '111979',
      isAuthenticated: false,
      isFirstLogin: true,
      products: [],
      purchases: [],
      sales: [],
      dishes: [],
      inventoryAudits: [],
      activityLogs: [],

      setLanguage: (lang) => set({ language: lang }),

      login: (inputPassword) => {
        const state = get();
        if (state.password === inputPassword) {
          set({ isAuthenticated: true });
          get().addLog('User Login', 'Successful authentication');
          return true;
        }
        return false;
      },

      changePassword: (newPassword) => {
        set({ password: newPassword, isFirstLogin: false });
        get().addLog('Password Changed', 'User updated initial password');
      },

      updatePassword: (current, newPass) => {
        const state = get();
        if (state.password === current) {
          set({ password: newPass, isFirstLogin: false });
          get().addLog('Password Changed', 'User manually updated password');
          return true;
        }
        return false;
      },

      addLog: (action, details) => set((state) => ({
        activityLogs: [
          {
            id: generateId(),
            timestamp: new Date().toISOString(),
            action,
            details,
            user: state.username
          },
          ...state.activityLogs
        ]
      })),

      clearLogs: () => set({ activityLogs: [] }),

      updateProductMinBalance: (id, minBalance) => {
        const product = get().products.find(p => p.id === id);
        set((state) => ({
          products: state.products.map(p => p.id === id ? { ...p, minBalance } : p)
        }));
        get().addLog('Min Balance Updated', `${product?.name || id} set to ${minBalance}`);
      },

      addProduct: (product) => {
        set((state) => ({ products: [...state.products, product] }));
        get().addLog('Product Created', `${product.name} (${product.unit})`);
      },

      addDish: (dish) => {
        set((state) => ({ dishes: [...state.dishes, dish] }));
        get().addLog('Dish Created', dish.name);
      },

      editDish: (id, dish) => {
        set((state) => ({ dishes: state.dishes.map(d => d.id === id ? dish : d) }));
        get().addLog('Dish Edited', dish.name);
      },

      deleteDish: (id) => {
        const dish = get().dishes.find(d => d.id === id);
        set((state) => ({ dishes: state.dishes.filter(d => d.id !== id) }));
        get().addLog('Dish Deleted', dish?.name || id);
      },

      deletePurchase: (id) => {
        const purchase = get().purchases.find(p => p.id === id);
        const product = get().products.find(p => p.id === purchase?.productId);
        set((state) => ({ purchases: state.purchases.filter(p => p.id !== id) }));
        get().addLog('Purchase Deleted', `${product?.name || 'Unknown'} x${purchase?.quantity || 0}`);
      },

      addSale: (saleData) => {
        const state = get();
        const dish = state.dishes.find(d => d.id === saleData.dishId);
        const totalRevenue = dish ? dish.salePrice * saleData.quantity : 0;

        const newSale: Sale = {
          id: generateId(),
          ...saleData,
          totalRevenue,
        };

        set((state) => ({ sales: [...state.sales, newSale] }));
        get().addLog('Sale Added', `${dish?.name || 'Unknown'} x${saleData.quantity}`);
      },

      editSale: (id, saleData) => {
        const dish = get().dishes.find(d => d.id === saleData.dishId);
        const totalRevenue = dish ? dish.salePrice * saleData.quantity : 0;

        set((state) => ({
          sales: state.sales.map(s => s.id === id ? { ...s, ...saleData, totalRevenue } : s)
        }));
        get().addLog('Sale Edited', `${dish?.name || 'Unknown'} x${saleData.quantity}`);
      },

      deleteSale: (id) => {
        const sale = get().sales.find(s => s.id === id);
        const dish = get().dishes.find(d => d.id === sale?.dishId);
        set((state) => ({ sales: state.sales.filter(s => s.id !== id) }));
        get().addLog('Sale Deleted', `${dish?.name || 'Unknown'} x${sale?.quantity || 0}`);
      },

      addPurchase: (purchaseData) => {
        const state = get();
        let existingProduct = state.products.find(
          p => p.name.toLowerCase() === purchaseData.productName.toLowerCase()
        );

        let newProducts = [...state.products];
        let productId = existingProduct?.id;

        if (!existingProduct) {
          productId = generateId();
          newProducts.push({
            id: productId,
            code: purchaseData.code,
            name: purchaseData.productName,
            unit: purchaseData.unit,
            category: purchaseData.category,
            minBalance: 0,
          });
        } else if (purchaseData.code && !existingProduct.code) {
          existingProduct.code = purchaseData.code;
        }

        const newPurchase: Purchase = {
          id: generateId(),
          date: purchaseData.date,
          productId: productId!,
          quantity: purchaseData.quantity,
          price: purchaseData.price,
          total: purchaseData.quantity * purchaseData.price,
        };

        set({
          products: newProducts,
          purchases: [...state.purchases, newPurchase],
        });

        get().addLog('Purchase Added', `${purchaseData.productName} x${purchaseData.quantity} ${purchaseData.unit}`);
      },

      editPurchase: (id, purchaseData) => {
        const state = get();
        let existingProduct = state.products.find(
          p => p.name.toLowerCase() === purchaseData.productName.toLowerCase()
        );

        let newProducts = [...state.products];
        let productId = existingProduct?.id;

        if (!existingProduct) {
          productId = generateId();
          newProducts.push({
            id: productId,
            code: purchaseData.code,
            name: purchaseData.productName,
            unit: purchaseData.unit,
            category: purchaseData.category,
            minBalance: 0,
          });
        } else if (purchaseData.code && !existingProduct.code) {
          existingProduct.code = purchaseData.code;
        }

        const updatedPurchases = state.purchases.map(p => 
          p.id === id ? {
            ...p,
            date: purchaseData.date,
            productId: productId!,
            quantity: purchaseData.quantity,
            price: purchaseData.price,
            total: purchaseData.quantity * purchaseData.price,
          } : p
        );

        set({
          products: newProducts,
          purchases: updatedPurchases,
        });

        get().addLog('Purchase Edited', `${purchaseData.productName} x${purchaseData.quantity} ${purchaseData.unit}`);
      },

      bulkAddPurchases: (bulkPurchases) => {
        const state = get();
        let newProducts = [...state.products];
        let newPurchases = [...state.purchases];

        bulkPurchases.forEach(purchaseData => {
          let existingProduct = newProducts.find(
            p => p.name.toLowerCase() === purchaseData.productName.toLowerCase()
          );

          let productId = existingProduct?.id;

          if (!existingProduct) {
            productId = generateId();
            newProducts.push({
              id: productId,
              code: purchaseData.code,
              name: purchaseData.productName,
              unit: purchaseData.unit,
              category: purchaseData.category || 'General',
              minBalance: 0,
            });
          } else if (purchaseData.code && !existingProduct.code) {
             existingProduct.code = purchaseData.code;
          }

          newPurchases.push({
            id: generateId(),
            date: purchaseData.date,
            productId: productId!,
            quantity: purchaseData.quantity,
            price: purchaseData.price,
            total: purchaseData.quantity * purchaseData.price,
          });
        });

        set({
          products: newProducts,
          purchases: newPurchases,
        });

        get().addLog('Bulk Import', `${bulkPurchases.length} purchases imported from Excel`);
      },

      saveInventoryAudit: (audit) => {
        const state = get();
        const existingIndex = state.inventoryAudits.findIndex(a => a.date === audit.date);
        const newAudits = [...state.inventoryAudits];

        if (existingIndex >= 0) {
          newAudits[existingIndex] = { ...newAudits[existingIndex], balances: audit.balances };
        } else {
          newAudits.push({ id: generateId(), ...audit });
        }

        set({ inventoryAudits: newAudits });
        get().addLog('Inventory Saved', `Audit for date ${audit.date}`);
      },

      clearAllData: () => {
        set({
          products: [],
          purchases: [],
          sales: [],
          dishes: [],
          inventoryAudits: [],
          activityLogs: []
        });
        get().addLog('System Wipe', 'All system data was completely wiped');
      },

      // THE CHEF'S GRAND OPENING TEST
      executeChefsGrandOpeningTest: () => {
        const today = new Date().toISOString().split('T')[0];

        // Wipe clean first
        set({ products: [], purchases: [], sales: [], dishes: [], inventoryAudits: [], activityLogs: [] });

        // Step 1: 100 High-Quality Ingredients
        const meats = ['Ribeye', 'Tenderloin', 'Lamb Chops', 'Pork Belly', 'Chicken Breast', 'Duck Breast', 'Veal Chop', 'Wagyu Beef', 'Quail', 'Venison'];
        const fish = ['Sea Bass', 'Salmon', 'Tuna', 'Shrimp', 'Scallops', 'Octopus', 'Squid', 'Lobster', 'Crab', 'Caviar'];
        const veg = ['Tomato', 'Cucumber', 'Onion', 'Mushroom', 'Eggplant', 'Zucchini', 'Red Bell Pepper', 'Green Bell Pepper', 'Potato', 'Carrot', 'Broccoli', 'Cauliflower', 'Asparagus', 'Spinach', 'Garlic', 'Cherry Tomato', 'Artichoke', 'Sweet Potato', 'Leek', 'Celery'];
        const herbs = ['Basil', 'Parsley', 'Tarragon', 'Mint', 'Coriander', 'Dill', 'Rosemary', 'Thyme', 'Oregano', 'Lemongrass'];
        const cheese = ['Sulguni', 'Imeretian', 'Gouda', 'Parmesan', 'Roquefort', 'Cheddar', 'Mozzarella', 'Camembert', 'Brie', 'Feta'];
        const spices = ['Saffron', 'Black Pepper', 'Salt', 'Paprika', 'Cumin', 'Turmeric', 'Cinnamon', 'Nutmeg', 'Cardamom', 'Chili Powder'];
        const dry = ['Truffle Oil', 'Olive Oil', 'Butter', 'Cream 18%', 'Milk', 'Eggs', 'Flour', 'Sugar', 'Rice', 'Pasta', 'Honey', 'Balsamic Vinegar', 'Soy Sauce', 'Walnuts', 'Almonds', 'Pine Nuts', 'Lemon', 'Orange', 'Apple', 'Truffles', 'Coffee Beans', 'Vanilla Extract', 'Mustard', 'White Wine', 'Red Wine', 'Chicken Stock', 'Beef Stock', 'Fish Stock', 'Yeast', 'Baking Powder'];

        const rawItems = [
          ...meats.map(n => ({ n, c: 'Meat/Fish', p: Math.floor(Math.random() * 20) + 25 })), // 25-45 GEL
          ...fish.map(n => ({ n, c: 'Meat/Fish', p: Math.floor(Math.random() * 20) + 25 })), // 25-45 GEL
          ...veg.map(n => ({ n, c: 'Produce', p: Math.floor(Math.random() * 8) + 3 })), // 3-10 GEL
          ...herbs.map(n => ({ n, c: 'Produce', p: Math.floor(Math.random() * 10) + 5 })), // 5-15 GEL
          ...cheese.map(n => ({ n, c: 'Dry/Dairy', p: Math.floor(Math.random() * 15) + 15 })), // 15-30 GEL
          ...spices.map(n => ({ n, c: 'Dry/Dairy', p: Math.floor(Math.random() * 45) + 5 })), // 5-50 GEL
          ...dry.map(n => ({ n, c: 'Dry/Dairy', p: Math.floor(Math.random() * 20) + 5 })) // 5-25 GEL
        ];

        const generatedProducts: Product[] = [];
        const generatedPurchases: Purchase[] = [];

        rawItems.forEach((item, idx) => {
          const pId = `PROD-CHEF-${idx}`;
          const u = (item.n === 'Eggs' || item.n === 'Caviar' || item.n === 'Saffron') ? 'pack' : (item.n.includes('Oil') || item.n.includes('Wine') || item.n.includes('Stock') || item.n === 'Milk') ? 'liter' : 'kg';

          generatedProducts.push({
            id: pId,
            code: `C${1000 + idx}`,
            name: item.n,
            unit: u,
            category: item.c,
            minBalance: 5
          });

          // Exactly 100 Units of everything
          generatedPurchases.push({
            id: `PUR-CHEF-${idx}`,
            date: today,
            productId: pId,
            quantity: 100,
            price: item.p,
            total: 100 * item.p
          });
        });

        // Step 2: 30 Signature Dishes
        const adjectives = ["Truffle-infused", "Pan-seared", "Roasted", "Confit", "Grilled", "Braised", "Smoked", "Poached", "Caramelized", "Spicy"];
        const nouns = ["Medley", "Delight", "Fusion", "Symphony", "Trio", "Essence", "Plate", "Bowl", "Experience", "Creation"];
        const generatedDishes: Dish[] = [];

        for(let i=0; i<30; i++) {
          const numIngredients = Math.floor(Math.random() * 5) + 4; // 4 to 8
          const shuffledProducts = [...generatedProducts].sort(() => 0.5 - Math.random());
          const selectedProducts = shuffledProducts.slice(0, numIngredients);

          const ingredients: Ingredient[] = selectedProducts.map(sp => {
            let loss = 5;
            if (sp.category === 'Meat/Fish') loss = 25;
            if (sp.category === 'Produce') loss = Math.floor(Math.random() * 6) + 15; // 15-20%

            return {
              productId: sp.id,
              quantity: Number((Math.random() * 0.2 + 0.05).toFixed(3)), // 0.05 to 0.25 net weight
              lossPercentage: loss
            }
          });

          const adj = adjectives[Math.floor(Math.random() * adjectives.length)];
          const noun = nouns[Math.floor(Math.random() * nouns.length)];
          const mainIngredient = selectedProducts[0].name;

          generatedDishes.push({
            id: `DISH-CHEF-${i}`,
            name: `${adj} ${mainIngredient} ${noun}`,
            category: 'Chef Signature',
            salePrice: Math.floor(Math.random() * 66) + 15, // 15 to 80 GEL
            ingredients
          });
        }

        // Step 3: Randomized Sales (15 dishes, 20 portions each)
        const generatedSales: Sale[] = [];
        const shuffledDishes = [...generatedDishes].sort(() => 0.5 - Math.random());
        const selectedDishes = shuffledDishes.slice(0, 15);

        selectedDishes.forEach((dish, idx) => {
          generatedSales.push({
            id: `SALE-CHEF-${idx}`,
            date: today,
            dishId: dish.id,
            quantity: 20,
            totalRevenue: 20 * dish.salePrice
          });
        });

        // Final Commit
        set({ 
          products: generatedProducts, 
          purchases: generatedPurchases, 
          dishes: generatedDishes, 
          sales: generatedSales, 
          inventoryAudits: [] 
        });

        get().addLog('System Test', 'Chef Grand Opening data generated successfully');
      },
    }),
    {
      name: 'cost-control-storage',
      storage: createJSONStorage(() => localStorage),
    }
  )
);

import React, { useState } from 'react';
import { useAppStore } from '../store';
import { t } from '../i18n';
import { Settings, User, Shield, Save, KeyRound, AlertCircle, CheckCircle2, History, ChevronDown, ChevronRight, Clock, Download, Trash2 } from 'lucide-react';
import * as XLSX from 'xlsx';

export const SettingsPage: React.FC = () => {
  const { language, username, updatePassword, activityLogs, clearLogs } = useAppStore();

  const [currentPassword, setCurrentPassword] = useState('');
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');

  // State for collapsible activity log
  const [isLogsExpanded, setIsLogsExpanded] = useState(false);

  const [alert, setAlert] = useState<{ message: string; type: 'success' | 'error' } | null>(null);
  const [confirmModal, setConfirmModal] = useState<{ message: string; onConfirm: () => void } | null>(null);

  const handlePasswordChange = (e: React.FormEvent) => {
    e.preventDefault();

    if (newPassword !== confirmPassword) {
      setAlert({ message: t(language, 'passwordMismatch'), type: 'error' });
      return;
    }

    const success = updatePassword(currentPassword, newPassword);

    if (success) {
      setAlert({ message: t(language, 'passwordChanged'), type: 'success' });
      setCurrentPassword('');
      setNewPassword('');
      setConfirmPassword('');
    } else {
      setAlert({ message: t(language, 'invalidCurrentPassword'), type: 'error' });
    }
  };

  // Helper to format timestamps based on active language
  const formatDateTime = (isoString: string) => {
    const d = new Date(isoString);
    return d.toLocaleString(language === 'ka' ? 'ka-GE' : 'en-US', {
      year: 'numeric', 
      month: 'short', 
      day: '2-digit',
      hour: '2-digit', 
      minute: '2-digit', 
      second: '2-digit'
    });
  };

  const handleExportLogs = () => {
    const dataToExport = activityLogs.map(log => ({
      [t(language, 'dateTime')]: formatDateTime(log.timestamp),
      [t(language, 'actionLabel')]: log.action,
      [t(language, 'detailsLabel')]: log.details,
    }));

    const worksheet = XLSX.utils.json_to_sheet(dataToExport);
    const workbook = XLSX.utils.book_new();
    // Excel sheet names cannot exceed 31 characters
    XLSX.utils.book_append_sheet(workbook, worksheet, t(language, 'activityHistoryTitle').substring(0, 31));
    XLSX.writeFile(workbook, `Activity_Logs_${new Date().toISOString().split('T')[0]}.xlsx`);
  };

  const requestClearLogs = () => {
    setConfirmModal({
      message: t(language, 'confirmClearLogs'),
      onConfirm: () => {
        clearLogs();
        setAlert({ message: t(language, 'logsCleared'), type: 'success' });
      }
    });
  };

  // Keep UI clean by showing a maximum of 50 recent logs
  const recentLogs = activityLogs.slice(0, 50);

  return (
    <div className="p-4 sm:p-6 max-w-5xl mx-auto w-full space-y-6">
      <div className="flex items-center space-x-3 mb-6">
        <div className="bg-brand-100 p-2.5 rounded-xl">
          <Settings className="w-6 h-6 text-brand-600" />
        </div>
        <div>
          <h2 className="text-2xl font-bold text-gray-900 tracking-tight">{t(language, 'settings')}</h2>
          <p className="text-sm text-gray-500 mt-0.5">{t(language, 'settingsDesc')}</p>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">

        {/* Profile Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-5 border-b border-gray-100 bg-gray-50/50 flex items-center">
            <User className="w-5 h-5 text-gray-500 mr-2" />
            <h3 className="text-lg font-bold text-gray-900">{t(language, 'profile')}</h3>
          </div>
          <div className="p-6">
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'username')}</label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <User className="w-4 h-4 text-gray-400" />
                  </div>
                  <input
                    type="text"
                    readOnly
                    value={username}
                    className="w-full pl-10 pr-4 py-2.5 bg-gray-100 border border-gray-300 rounded-xl text-gray-600 font-medium sm:text-sm shadow-inner cursor-not-allowed"
                  />
                </div>
                <p className="mt-2 text-xs text-gray-500">
                  {language === 'ka' ? 'მომხმარებლის სახელის შეცვლა შეუძლებელია.' : 'Username cannot be changed.'}
                </p>
              </div>
            </div>
          </div>
        </div>

        {/* Security / Password Change Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="p-5 border-b border-gray-100 bg-gray-50/50 flex items-center">
            <Shield className="w-5 h-5 text-gray-500 mr-2" />
            <h3 className="text-lg font-bold text-gray-900">{t(language, 'security')}</h3>
          </div>
          <div className="p-6">
            <form onSubmit={handlePasswordChange} className="space-y-5">

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'currentPassword')}</label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <KeyRound className="w-4 h-4 text-gray-400" />
                  </div>
                  <input
                    type="password"
                    required
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-300 rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-brand-500 sm:text-sm transition-shadow shadow-sm"
                  />
                </div>
              </div>

              <div className="border-t border-gray-100 pt-5">
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'newPassword')}</label>
                <input
                  type="password"
                  required
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="w-full px-4 py-2.5 bg-white border border-gray-300 rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-brand-500 sm:text-sm transition-shadow shadow-sm mb-4"
                />

                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'confirmPassword')}</label>
                <input
                  type="password"
                  required
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="w-full px-4 py-2.5 bg-white border border-gray-300 rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-brand-500 sm:text-sm transition-shadow shadow-sm"
                />
              </div>

              <button
                type="submit"
                className="w-full flex justify-center items-center px-4 py-3 bg-brand-600 text-white rounded-xl text-sm font-bold hover:bg-brand-700 transition-all shadow-sm active:scale-95 focus:outline-none focus:ring-2 focus:ring-brand-500 focus:ring-offset-2 mt-2"
              >
                <Save className="w-4 h-4 mr-2" />
                {t(language, 'changePassword')}
              </button>
            </form>
          </div>
        </div>

      </div>

      {/* Activity Log Viewer (Collapsible) */}
      <div className="bg-slate-50 border border-slate-200 rounded-2xl shadow-sm overflow-hidden mt-8 transition-all duration-300">
        <button
          onClick={() => setIsLogsExpanded(!isLogsExpanded)}
          className="w-full px-5 py-4 flex items-center justify-between hover:bg-slate-100/80 transition-colors focus:outline-none"
        >
          <div className="flex items-center space-x-3">
            <div className={`p-2 rounded-xl transition-colors ${isLogsExpanded ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
              <History className="w-5 h-5" />
            </div>
            <h3 className="text-lg font-bold text-slate-800">{t(language, 'activityHistoryTitle')}</h3>
          </div>
          <div className={`p-1.5 rounded-lg transition-colors ${isLogsExpanded ? 'bg-indigo-50 text-indigo-500' : 'text-slate-400'}`}>
            {isLogsExpanded ? <ChevronDown className="w-5 h-5" /> : <ChevronRight className="w-5 h-5" />}
          </div>
        </button>

        {isLogsExpanded && (
          <div className="border-t border-slate-200 px-5 pb-5 pt-4">

            {/* Toolbar for Logs */}
            <div className="flex flex-col sm:flex-row justify-end items-center mb-4 space-y-3 sm:space-y-0 sm:space-x-3">
              <button
                onClick={handleExportLogs}
                disabled={activityLogs.length === 0}
                className="w-full sm:w-auto flex items-center justify-center px-4 py-2 bg-white border border-gray-300 rounded-xl text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Download className="w-4 h-4 mr-2" />
                {t(language, 'exportExcel')}
              </button>
              <button
                onClick={requestClearLogs}
                disabled={activityLogs.length === 0}
                className="w-full sm:w-auto flex items-center justify-center px-4 py-2 bg-red-50 border border-red-200 rounded-xl text-sm font-medium text-red-600 hover:bg-red-100 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Trash2 className="w-4 h-4 mr-2" />
                {t(language, 'clearLogs')}
              </button>
            </div>

            <div className="overflow-x-auto bg-white rounded-xl border border-slate-200 shadow-sm">
              <table className="min-w-full divide-y divide-slate-100 text-sm">
                <thead className="bg-slate-50">
                  <tr>
                    <th className="px-5 py-3 text-left font-bold text-slate-500 uppercase tracking-wider">{t(language, 'dateTime')}</th>
                    <th className="px-5 py-3 text-left font-bold text-slate-500 uppercase tracking-wider">{t(language, 'actionLabel')}</th>
                    <th className="px-5 py-3 text-left font-bold text-slate-500 uppercase tracking-wider">{t(language, 'detailsLabel')}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {recentLogs.length === 0 ? (
                    <tr>
                      <td colSpan={3} className="px-5 py-8 text-center text-slate-400">
                        <div className="flex flex-col items-center">
                          <Clock className="w-8 h-8 mb-2 opacity-30" />
                          <p className="font-medium">{t(language, 'noLogs')}</p>
                        </div>
                      </td>
                    </tr>
                  ) : (
                    recentLogs.map((log) => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-5 py-3 whitespace-nowrap text-slate-500 font-medium">
                          {formatDateTime(log.timestamp)}
                        </td>
                        <td className="px-5 py-3 whitespace-nowrap font-bold text-slate-700">
                          {log.action}
                        </td>
                        <td className="px-5 py-3 text-slate-600">
                          {log.details}
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
              {activityLogs.length > 50 && (
                <div className="bg-slate-50 p-3 text-center text-xs font-semibold text-slate-500 border-t border-slate-100">
                  Showing the 50 most recent logs out of {activityLogs.length} total entries.
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Delete Confirmation Modal */}
      {confirmModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all text-center">
            <h3 className="text-lg font-bold text-gray-900 mb-2">ყურადღება / Warning</h3>
            <p className="text-sm text-gray-600 mb-6">{confirmModal.message}</p>
            <div className="flex space-x-3">
              <button 
                onClick={() => setConfirmModal(null)} 
                className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-xl hover:bg-gray-50 font-medium transition-colors"
              >
                {t(language, 'cancel')}
              </button>
              <button 
                onClick={() => { confirmModal.onConfirm(); setConfirmModal(null); }} 
                className="flex-1 px-4 py-2 bg-red-600 text-white rounded-xl hover:bg-red-700 font-bold shadow-sm transition-all"
              >
                {t(language, 'clearLogs')}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Custom Alert Modal */}
      {alert && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all text-center">
            {alert.type === 'success' ? (
              <CheckCircle2 className="w-12 h-12 text-green-500 mx-auto mb-3" />
            ) : (
              <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-3" />
            )}
            <h3 className="text-lg font-bold text-gray-900 mb-2">
              {alert.type === 'success' ? (language === 'ka' ? 'წარმატება' : 'Success') : (language === 'ka' ? 'შეცდომა' : 'Error')}
            </h3>
            <p className="text-sm text-gray-600 mb-6">{alert.message}</p>
            <button 
              onClick={() => setAlert(null)} 
              className={`w-full px-4 py-2.5 text-white rounded-xl font-bold shadow-sm transition-all active:scale-95 ${
                alert.type === 'success' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'
              }`}
            >
              OK
            </button>
          </div>
        </div>
      )}

    </div>
  );
};

import { create } from 'zustand';
import { persist, createJSONStorage } from 'zustand/middleware';
import { Product, Purchase, Sale, Dish, Language, InventoryAudit, Ingredient, ActivityLog } from './types';

interface AppState {
  language: Language;
  username: string;
  password: string;
  isAuthenticated: boolean;
  isFirstLogin: boolean;
  products: Product[];
  purchases: Purchase[];
  sales: Sale[];
  dishes: Dish[];
  inventoryAudits: InventoryAudit[];
  activityLogs: ActivityLog[];
  setLanguage: (lang: Language) => void;
  login: (inputPassword: string) => boolean;
  logout: () => void;
  changePassword: (newPassword: string) => void;
  updatePassword: (current: string, newPass: string) => boolean;
  addLog: (action: string, details: string) => void;
  clearLogs: () => void;
  updateProductMinBalance: (id: string, minBalance: number) => void;
  addPurchase: (purchase: Omit<Purchase, 'id' | 'total' | 'productId'> & { productName: string, unit: string, category: string, code?: string }) => void;
  editPurchase: (id: string, purchase: Omit<Purchase, 'id' | 'total' | 'productId'> & { productName: string, unit: string, category: string, code?: string }) => void;
  bulkAddPurchases: (purchases: Array<Omit<Purchase, 'id' | 'total' | 'productId'> & { productName: string, unit: string, category: string, code?: string }>) => void;
  deletePurchase: (id: string) => void;
  addSale: (sale: Omit<Sale, 'id' | 'totalRevenue'>) => void;
  editSale: (id: string, sale: Omit<Sale, 'id' | 'totalRevenue'>) => void;
  deleteSale: (id: string) => void;
  addProduct: (product: Product) => void;
  addDish: (dish: Dish) => void;
  editDish: (id: string, dish: Dish) => void;
  deleteDish: (id: string) => void;
  saveInventoryAudit: (audit: Omit<InventoryAudit, 'id'>) => void;
  clearAllData: () => void;
  executeChefsGrandOpeningTest: () => void;
}

const generateId = () => Math.random().toString(36).substring(2, 11);

// Standard Yield Formula: Net Quantity / (1 - LossPercentage / 100)
const getGrossQuantity = (netQuantity: number, lossPercentage: number = 0): number => {
  const validLoss = Math.min(Math.max(lossPercentage, 0), 99); // Prevent division by zero
  return netQuantity / (1 - (validLoss / 100));
};

export const useAppStore = create<AppState>()(
  persist(
    (set, get) => ({
      language: 'ka',
      username: 'Administrator',
      password: '111979',
      isAuthenticated: false,
      isFirstLogin: true,
      products: [],
      purchases: [],
      sales: [],
      dishes: [],
      inventoryAudits: [],
      activityLogs: [],

      setLanguage: (lang) => set({ language: lang }),

      login: (inputPassword) => {
        const state = get();
        if (state.password === inputPassword) {
          set({ isAuthenticated: true });
          get().addLog('User Login', 'Successful authentication');
          return true;
        }
        return false;
      },

      logout: () => {
        set({ isAuthenticated: false });
        get().addLog('User Logout', 'User ended session');
      },

      changePassword: (newPassword) => {
        set({ password: newPassword, isFirstLogin: false });
        get().addLog('Password Changed', 'User updated initial password');
      },

      updatePassword: (current, newPass) => {
        const state = get();
        if (state.password === current) {
          set({ password: newPass, isFirstLogin: false });
          get().addLog('Password Changed', 'User manually updated password');
          return true;
        }
        return false;
      },

      addLog: (action, details) => set((state) => ({
        activityLogs: [
          {
            id: generateId(),
            timestamp: new Date().toISOString(),
            action,
            details,
            user: state.username
          },
          ...state.activityLogs
        ]
      })),

      clearLogs: () => set({ activityLogs: [] }),

      updateProductMinBalance: (id, minBalance) => {
        const product = get().products.find(p => p.id === id);
        set((state) => ({
          products: state.products.map(p => p.id === id ? { ...p, minBalance } : p)
        }));
        get().addLog('Min Balance Updated', `${product?.name || id} set to ${minBalance}`);
      },

      addProduct: (product) => {
        set((state) => ({ products: [...state.products, product] }));
        get().addLog('Product Created', `${product.name} (${product.unit})`);
      },

      addDish: (dish) => {
        set((state) => ({ dishes: [...state.dishes, dish] }));
        get().addLog('Dish Created', dish.name);
      },

      editDish: (id, dish) => {
        set((state) => ({ dishes: state.dishes.map(d => d.id === id ? dish : d) }));
        get().addLog('Dish Edited', dish.name);
      },

      deleteDish: (id) => {
        const dish = get().dishes.find(d => d.id === id);
        set((state) => ({ dishes: state.dishes.filter(d => d.id !== id) }));
        get().addLog('Dish Deleted', dish?.name || id);
      },

      deletePurchase: (id) => {
        const purchase = get().purchases.find(p => p.id === id);
        const product = get().products.find(p => p.id === purchase?.productId);
        set((state) => ({ purchases: state.purchases.filter(p => p.id !== id) }));
        get().addLog('Purchase Deleted', `${product?.name || 'Unknown'} x${purchase?.quantity || 0}`);
      },

      addSale: (saleData) => {
        const state = get();
        const dish = state.dishes.find(d => d.id === saleData.dishId);
        const totalRevenue = dish ? dish.salePrice * saleData.quantity : 0;

        const newSale: Sale = {
          id: generateId(),
          ...saleData,
          totalRevenue,
        };

        set((state) => ({ sales: [...state.sales, newSale] }));
        get().addLog('Sale Added', `${dish?.name || 'Unknown'} x${saleData.quantity}`);
      },

      editSale: (id, saleData) => {
        const dish = get().dishes.find(d => d.id === saleData.dishId);
        const totalRevenue = dish ? dish.salePrice * saleData.quantity : 0;

        set((state) => ({
          sales: state.sales.map(s => s.id === id ? { ...s, ...saleData, totalRevenue } : s)
        }));
        get().addLog('Sale Edited', `${dish?.name || 'Unknown'} x${saleData.quantity}`);
      },

      deleteSale: (id) => {
        const sale = get().sales.find(s => s.id === id);
        const dish = get().dishes.find(d => d.id === sale?.dishId);
        set((state) => ({ sales: state.sales.filter(s => s.id !== id) }));
        get().addLog('Sale Deleted', `${dish?.name || 'Unknown'} x${sale?.quantity || 0}`);
      },

      addPurchase: (purchaseData) => {
        const state = get();
        let existingProduct = state.products.find(
          p => p.name.toLowerCase() === purchaseData.productName.toLowerCase()
        );

        let newProducts = [...state.products];
        let productId = existingProduct?.id;

        if (!existingProduct) {
          productId = generateId();
          newProducts.push({
            id: productId,
            code: purchaseData.code,
            name: purchaseData.productName,
            unit: purchaseData.unit,
            category: purchaseData.category,
            minBalance: 0,
          });
        } else if (purchaseData.code && !existingProduct.code) {
          existingProduct.code = purchaseData.code;
        }

        const newPurchase: Purchase = {
          id: generateId(),
          date: purchaseData.date,
          productId: productId!,
          quantity: purchaseData.quantity,
          price: purchaseData.price,
          total: purchaseData.quantity * purchaseData.price,
        };

        set({
          products: newProducts,
          purchases: [...state.purchases, newPurchase],
        });

        get().addLog('Purchase Added', `${purchaseData.productName} x${purchaseData.quantity} ${purchaseData.unit}`);
      },

      editPurchase: (id, purchaseData) => {
        const state = get();
        let existingProduct = state.products.find(
          p => p.name.toLowerCase() === purchaseData.productName.toLowerCase()
        );

        let newProducts = [...state.products];
        let productId = existingProduct?.id;

        if (!existingProduct) {
          productId = generateId();
          newProducts.push({
            id: productId,
            code: purchaseData.code,
            name: purchaseData.productName,
            unit: purchaseData.unit,
            category: purchaseData.category,
            minBalance: 0,
          });
        } else if (purchaseData.code && !existingProduct.code) {
          existingProduct.code = purchaseData.code;
        }

        const updatedPurchases = state.purchases.map(p => 
          p.id === id ? {
            ...p,
            date: purchaseData.date,
            productId: productId!,
            quantity: purchaseData.quantity,
            price: purchaseData.price,
            total: purchaseData.quantity * purchaseData.price,
          } : p
        );

        set({
          products: newProducts,
          purchases: updatedPurchases,
        });

        get().addLog('Purchase Edited', `${purchaseData.productName} x${purchaseData.quantity} ${purchaseData.unit}`);
      },

      bulkAddPurchases: (bulkPurchases) => {
        const state = get();
        let newProducts = [...state.products];
        let newPurchases = [...state.purchases];

        bulkPurchases.forEach(purchaseData => {
          let existingProduct = newProducts.find(
            p => p.name.toLowerCase() === purchaseData.productName.toLowerCase()
          );

          let productId = existingProduct?.id;

          if (!existingProduct) {
            productId = generateId();
            newProducts.push({
              id: productId,
              code: purchaseData.code,
              name: purchaseData.productName,
              unit: purchaseData.unit,
              category: purchaseData.category || 'General',
              minBalance: 0,
            });
          } else if (purchaseData.code && !existingProduct.code) {
             existingProduct.code = purchaseData.code;
          }

          newPurchases.push({
            id: generateId(),
            date: purchaseData.date,
            productId: productId!,
            quantity: purchaseData.quantity,
            price: purchaseData.price,
            total: purchaseData.quantity * purchaseData.price,
          });
        });

        set({
          products: newProducts,
          purchases: newPurchases,
        });

        get().addLog('Bulk Import', `${bulkPurchases.length} purchases imported from Excel`);
      },

      saveInventoryAudit: (audit) => {
        const state = get();
        const existingIndex = state.inventoryAudits.findIndex(a => a.date === audit.date);
        const newAudits = [...state.inventoryAudits];

        if (existingIndex >= 0) {
          newAudits[existingIndex] = { ...newAudits[existingIndex], balances: audit.balances };
        } else {
          newAudits.push({ id: generateId(), ...audit });
        }

        set({ inventoryAudits: newAudits });
        get().addLog('Inventory Saved', `Audit for date ${audit.date}`);
      },

      clearAllData: () => {
        set({
          products: [],
          purchases: [],
          sales: [],
          dishes: [],
          inventoryAudits: [],
          activityLogs: []
        });
        get().addLog('System Wipe', 'All system data was completely wiped');
      },

      // THE CHEF'S GRAND OPENING TEST
      executeChefsGrandOpeningTest: () => {
        const today = new Date().toISOString().split('T')[0];

        // Wipe clean first
        set({ products: [], purchases: [], sales: [], dishes: [], inventoryAudits: [], activityLogs: [] });

        // Step 1: 100 High-Quality Ingredients
        const meats = ['Ribeye', 'Tenderloin', 'Lamb Chops', 'Pork Belly', 'Chicken Breast', 'Duck Breast', 'Veal Chop', 'Wagyu Beef', 'Quail', 'Venison'];
        const fish = ['Sea Bass', 'Salmon', 'Tuna', 'Shrimp', 'Scallops', 'Octopus', 'Squid', 'Lobster', 'Crab', 'Caviar'];
        const veg = ['Tomato', 'Cucumber', 'Onion', 'Mushroom', 'Eggplant', 'Zucchini', 'Red Bell Pepper', 'Green Bell Pepper', 'Potato', 'Carrot', 'Broccoli', 'Cauliflower', 'Asparagus', 'Spinach', 'Garlic', 'Cherry Tomato', 'Artichoke', 'Sweet Potato', 'Leek', 'Celery'];
        const herbs = ['Basil', 'Parsley', 'Tarragon', 'Mint', 'Coriander', 'Dill', 'Rosemary', 'Thyme', 'Oregano', 'Lemongrass'];
        const cheese = ['Sulguni', 'Imeretian', 'Gouda', 'Parmesan', 'Roquefort', 'Cheddar', 'Mozzarella', 'Camembert', 'Brie', 'Feta'];
        const spices = ['Saffron', 'Black Pepper', 'Salt', 'Paprika', 'Cumin', 'Turmeric', 'Cinnamon', 'Nutmeg', 'Cardamom', 'Chili Powder'];
        const dry = ['Truffle Oil', 'Olive Oil', 'Butter', 'Cream 18%', 'Milk', 'Eggs', 'Flour', 'Sugar', 'Rice', 'Pasta', 'Honey', 'Balsamic Vinegar', 'Soy Sauce', 'Walnuts', 'Almonds', 'Pine Nuts', 'Lemon', 'Orange', 'Apple', 'Truffles', 'Coffee Beans', 'Vanilla Extract', 'Mustard', 'White Wine', 'Red Wine', 'Chicken Stock', 'Beef Stock', 'Fish Stock', 'Yeast', 'Baking Powder'];

        const rawItems = [
          ...meats.map(n => ({ n, c: 'Meat/Fish', p: Math.floor(Math.random() * 20) + 25 })), // 25-45 GEL
          ...fish.map(n => ({ n, c: 'Meat/Fish', p: Math.floor(Math.random() * 20) + 25 })), // 25-45 GEL
          ...veg.map(n => ({ n, c: 'Produce', p: Math.floor(Math.random() * 8) + 3 })), // 3-10 GEL
          ...herbs.map(n => ({ n, c: 'Produce', p: Math.floor(Math.random() * 10) + 5 })), // 5-15 GEL
