                  className="flex-1 flex justify-center items-center px-4 py-3 bg-white text-gray-700 rounded-xl text-sm font-bold hover:bg-gray-50 transition-colors shadow-sm focus:outline-none focus:ring-2 focus:ring-gray-300 border border-gray-300"
                >
                  <UploadCloud className="w-4 h-4 mr-2" />
                  {t(language, 'restoreData')}
                </button>
              </div>
            </div>
          </div>
        </div>

        {/* Security / Password Change Card */}
        <div className="bg-white rounded-2xl shadow-sm border border-gray-200 overflow-hidden h-fit">
          <div className="p-5 border-b border-gray-100 bg-gray-50/50 flex items-center">
            <Shield className="w-5 h-5 text-gray-500 mr-2" />
            <h3 className="text-lg font-bold text-gray-900">{t(language, 'security')}</h3>
          </div>
          <div className="p-6">
            <form onSubmit={handlePasswordChange} className="space-y-5">

              <div>
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'currentPassword')}</label>
                <div className="relative">
                  <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                    <KeyRound className="w-4 h-4 text-gray-400" />
                  </div>
                  <input
                    type="password"
                    required
                    value={currentPassword}
                    onChange={(e) => setCurrentPassword(e.target.value)}
                    className="w-full pl-10 pr-4 py-2.5 bg-white border border-gray-300 rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-brand-500 sm:text-sm transition-shadow shadow-sm"
                  />
                </div>
              </div>

              <div className="border-t border-gray-100 pt-5">
                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'newPassword')}</label>
                <input
                  type="password"
                  required
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="w-full px-4 py-2.5 bg-white border border-gray-300 rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-brand-500 sm:text-sm transition-shadow shadow-sm mb-4"
                />

                <label className="block text-sm font-semibold text-gray-700 mb-1.5">{t(language, 'confirmPassword')}</label>
                <input
                  type="password"
                  required
                  value={confirmPassword}
                  onChange={(e) => setConfirmPassword(e.target.value)}
                  className="w-full px-4 py-2.5 bg-white border border-gray-300 rounded-xl focus:ring-2 focus:ring-brand-500 focus:border-brand-500 sm:text-sm transition-shadow shadow-sm"
                />
              </div>

              <button
                type="submit"
                className="w-full flex justify-center items-center px-4 py-3 bg-brand-600 text-white rounded-xl text-sm font-bold hover:bg-brand-700 transition-all shadow-sm active:scale-95 focus:outline-none focus:ring-2 focus:ring-brand-500 focus:ring-offset-2 mt-2"
              >
                <Save className="w-4 h-4 mr-2" />
                {t(language, 'changePassword')}
              </button>
            </form>
          </div>
        </div>

      </div>

      {/* Activity Log Viewer (Collapsible) */}
      <div className="bg-slate-50 border border-slate-200 rounded-2xl shadow-sm overflow-hidden mt-8 transition-all duration-300">
        <button
          onClick={() => setIsLogsExpanded(!isLogsExpanded)}
          className="w-full px-5 py-4 flex items-center justify-between hover:bg-slate-100/80 transition-colors focus:outline-none"
        >
          <div className="flex items-center space-x-3">
            <div className={`p-2 rounded-xl transition-colors ${isLogsExpanded ? 'bg-indigo-100 text-indigo-600' : 'bg-slate-200 text-slate-500'}`}>
              <History className="w-5 h-5" />
            </div>
            <h3 className="text-lg font-bold text-slate-800">{t(language, 'activityHistoryTitle')}</h3>
          </div>
          <div className={`p-1.5 rounded-lg transition-colors ${isLogsExpanded ? 'bg-indigo-50 text-indigo-500' : 'text-slate-400'}`}>
            {isLogsExpanded ? <ChevronDown className="w-5 h-5" /> : <ChevronRight className="w-5 h-5" />}
          </div>
        </button>

        {isLogsExpanded && (
          <div className="border-t border-slate-200 px-5 pb-5 pt-4">

            {/* Toolbar for Logs */}
            <div className="flex flex-col sm:flex-row justify-end items-center mb-4 space-y-3 sm:space-y-0 sm:space-x-3">
              <button
                onClick={handleExportLogs}
                disabled={activityLogs.length === 0}
                className="w-full sm:w-auto flex items-center justify-center px-4 py-2 bg-white border border-gray-300 rounded-xl text-sm font-medium text-gray-700 hover:bg-gray-50 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Download className="w-4 h-4 mr-2" />
                {t(language, 'exportExcel')}
              </button>
              <button
                onClick={requestClearLogs}
                disabled={activityLogs.length === 0}
                className="w-full sm:w-auto flex items-center justify-center px-4 py-2 bg-red-50 border border-red-200 rounded-xl text-sm font-medium text-red-600 hover:bg-red-100 transition-colors shadow-sm disabled:opacity-50 disabled:cursor-not-allowed"
              >
                <Trash2 className="w-4 h-4 mr-2" />
                {t(language, 'clearLogs')}
              </button>
            </div>

            <div className="overflow-x-auto bg-white rounded-xl border border-slate-200 shadow-sm">
              <table className="min-w-full divide-y divide-slate-100 text-sm">
                <thead className="bg-slate-50">
                  <tr>
                    <th className="px-5 py-3 text-left font-bold text-slate-500 uppercase tracking-wider">{t(language, 'dateTime')}</th>
                    <th className="px-5 py-3 text-left font-bold text-slate-500 uppercase tracking-wider">{t(language, 'actionLabel')}</th>
                    <th className="px-5 py-3 text-left font-bold text-slate-500 uppercase tracking-wider">{t(language, 'detailsLabel')}</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-100">
                  {recentLogs.length === 0 ? (
                    <tr>
                      <td colSpan={3} className="px-5 py-8 text-center text-slate-400">
                        <div className="flex flex-col items-center">
                          <Clock className="w-8 h-8 mb-2 opacity-30" />
                          <p className="font-medium">{t(language, 'noLogs')}</p>
                        </div>
                      </td>
                    </tr>
                  ) : (
                    recentLogs.map((log) => (
                      <tr key={log.id} className="hover:bg-slate-50 transition-colors">
                        <td className="px-5 py-3 whitespace-nowrap text-slate-500 font-medium">
                          {formatDateTime(log.timestamp)}
                        </td>
                        <td className="px-5 py-3 whitespace-nowrap font-bold text-slate-700">
                          {log.action}
                        </td>
                        <td className="px-5 py-3 text-slate-600">
                          {log.details}
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
              {activityLogs.length > 50 && (
                <div className="bg-slate-50 p-3 text-center text-xs font-semibold text-slate-500 border-t border-slate-100">
                  Showing the 50 most recent logs out of {activityLogs.length} total entries.
                </div>
              )}
            </div>
          </div>
        )}
      </div>

      {/* Reusable Confirmation Modal */}
      {confirmModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all text-center">
            <h3 className="text-lg font-bold text-gray-900 mb-2">ყურადღება / Warning</h3>
            <p className="text-sm text-gray-600 mb-6">{confirmModal.message}</p>
            <div className="flex space-x-3">
              <button 
                onClick={() => {
                  setConfirmModal(null);
                  setPendingRestoreData(null);
                }} 
                className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-xl hover:bg-gray-50 font-medium transition-colors"
              >
                {t(language, 'cancel')}
              </button>
              <button 
                onClick={() => { confirmModal.onConfirm(); setConfirmModal(null); }} 
                className="flex-1 px-4 py-2 bg-red-600 text-white rounded-xl hover:bg-red-700 font-bold shadow-sm transition-all"
              >
                {pendingRestoreData ? (language === 'ka' ? 'აღდგენა' : 'Restore') : t(language, 'clearLogs')}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Custom Alert Modal */}
      {alert && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all text-center">
            {alert.type === 'success' ? (
              <CheckCircle2 className="w-12 h-12 text-green-500 mx-auto mb-3" />
            ) : (
              <AlertCircle className="w-12 h-12 text-red-500 mx-auto mb-3" />
            )}
            <h3 className="text-lg font-bold text-gray-900 mb-2">
              {alert.type === 'success' ? (language === 'ka' ? 'წარმატება' : 'Success') : (language === 'ka' ? 'შეცდომა' : 'Error')}
            </h3>
            <p className="text-sm text-gray-600 mb-6">{alert.message}</p>
            <button 
              onClick={() => setAlert(null)} 
              className={`w-full px-4 py-2.5 text-white rounded-xl font-bold shadow-sm transition-all active:scale-95 ${
                alert.type === 'success' ? 'bg-green-600 hover:bg-green-700' : 'bg-red-600 hover:bg-red-700'
              }`}
            >
              OK
            </button>
          </div>
        </div>
      )}

    </div>
  );
};

import React, { useState } from 'react';
import { Navigate, useNavigate, useLocation } from 'react-router-dom';
import { useAppStore } from '../store';
import { t } from '../i18n';
import { Lock, ArrowRight, AlertCircle, ChefHat } from 'lucide-react';

export const LoginPage: React.FC = () => {
  const { language, login, isAuthenticated } = useAppStore();
  const navigate = useNavigate();
  const location = useLocation();

  const [password, setPassword] = useState('');
  const [error, setError] = useState('');

  // Determine where to send the user after a successful login.
  // If they were intercepted by RequireAuth, send them back to their requested URL.
  const from = location.state?.from?.pathname || '/HORECA/COSTCONTROL/123456789/dashboard';

  // If already authenticated, redirect to the app securely
  if (isAuthenticated) {
    return <Navigate to={from} replace />;
  }

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const success = login(password);
    if (success) {
      navigate(from, { replace: true });
    } else {
      setError(t(language, 'invalidPassword'));
      setPassword('');
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex items-center justify-center p-4">
      <div className="max-w-md w-full">
        {/* Logo / Header */}
        <div className="text-center mb-8">
          <div className="inline-flex items-center justify-center w-16 h-16 rounded-2xl bg-brand-600 text-white shadow-lg shadow-brand-500/30 mb-4">
            <ChefHat className="w-8 h-8" />
          </div>
          <h1 className="text-3xl font-black text-slate-900 tracking-tight mb-2">
            {t(language, 'appTitle')}
          </h1>
          <p className="text-slate-500 font-medium">
            {t(language, 'loginSubtitle')}
          </p>
        </div>

        {/* Login Card */}
        <div className="bg-white rounded-3xl shadow-xl border border-slate-100 p-8">
          <form onSubmit={handleSubmit} className="space-y-6">

            <div>
              <label className="block text-sm font-bold text-slate-700 mb-2">
                {t(language, 'enterPassword')}
              </label>
              <div className="relative">
                <div className="absolute inset-y-0 left-0 pl-4 flex items-center pointer-events-none">
                  <Lock className="w-5 h-5 text-slate-400" />
                </div>
                <input
                  type="password"
                  required
                  autoFocus
                  value={password}
                  onChange={(e) => {
                    setPassword(e.target.value);
                    setError('');
                  }}
                  className={`w-full pl-12 pr-4 py-3.5 bg-slate-50 border rounded-xl text-slate-900 font-medium transition-all outline-none focus:ring-2 focus:ring-brand-500 focus:bg-white ${
                    error ? 'border-red-300 focus:ring-red-500' : 'border-slate-200'
                  }`}
                  placeholder="••••••"
                />
              </div>
              {error && (
                <div className="flex items-center mt-3 text-red-600 text-sm font-medium animate-in fade-in slide-in-from-top-1">
                  <AlertCircle className="w-4 h-4 mr-1.5 shrink-0" />
                  {error}
                </div>
              )}
            </div>

            <button
              type="submit"
              className="w-full flex justify-center items-center px-4 py-3.5 bg-brand-600 text-white rounded-xl text-base font-bold hover:bg-brand-700 transition-all shadow-md hover:shadow-lg active:scale-[0.98] group"
            >
              {t(language, 'loginButton')}
              <ArrowRight className="w-5 h-5 ml-2 opacity-70 group-hover:opacity-100 group-hover:translate-x-1 transition-all" />
            </button>

          </form>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { NavLink, useNavigate, useParams } from 'react-router-dom';
import { useAppStore } from '../store';
import { t } from '../i18n';
import { 
  LayoutDashboard, 
  Utensils, 
  TrendingUp, 
  ShoppingCart, 
  Package, 
  Boxes,
  X,
  Trash2,
  Settings,
  BookOpen,
  LineChart,
  LogOut
} from 'lucide-react';

interface SidebarProps {
  isOpen: boolean;
  setIsOpen: (isOpen: boolean) => void;
}

export const Sidebar: React.FC<SidebarProps> = ({ isOpen, setIsOpen }) => {
  const { language, clearAllData, logout } = useAppStore();
  const { restaurantId } = useParams<{ restaurantId: string }>();
  const navigate = useNavigate();
  const [confirmModal, setConfirmModal] = useState<{message: string, onConfirm: () => void} | null>(null);
  const [alertMessage, setAlertMessage] = useState<string | null>(null);

  const basePath = `/HORECA/COSTCONTROL/${restaurantId}`;

  const navItems = [
    { path: `${basePath}/dashboard`, label: t(language, 'dashboard'), icon: LayoutDashboard },
    { path: `${basePath}/menu`, label: t(language, 'menu'), icon: Utensils },
    { path: `${basePath}/sales`, label: t(language, 'sales'), icon: TrendingUp },
    { path: `${basePath}/purchases`, label: t(language, 'purchases'), icon: ShoppingCart },
    { path: `${basePath}/inventory`, label: t(language, 'inventory'), icon: Package },
    { path: `${basePath}/products`, label: t(language, 'products'), icon: Boxes },
    { path: `${basePath}/ai-analytics`, label: t(language, 'aiInsights'), icon: LineChart },
  ];

  const bottomNavItems = [
    { path: `${basePath}/settings`, label: language === 'ka' ? 'პარამეტრები' : 'Settings', icon: Settings },
    { path: `${basePath}/instructions`, label: language === 'ka' ? 'ინსტრუქცია' : 'Guide', icon: BookOpen },
  ];

  const handleClearData = () => {
    setConfirmModal({
      message: 'WARNING: Are you sure you want to completely Reset for Production? This will permanently wipe ALL DATA from the system.',
      onConfirm: () => {
        // Safe clear: Wipes products, dishes, sales, purchases, and audits, but keeps Auth State & Settings intact.
        clearAllData(); 

        setAlertMessage('System successfully reset for production use. Reloading...');
        setTimeout(() => {
          window.location.reload();
        }, 1500);
      }
    });
  };

  const handleLogout = () => {
    logout();
    setIsOpen(false);
    navigate('/login', { replace: true });
  };

  return (
    <>
      {/* Mobile Backdrop */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-20 md:hidden"
          onClick={() => setIsOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-slate-300 flex flex-col h-full transform transition-transform duration-300 ease-in-out md:relative md:translate-x-0 ${isOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-16 flex items-center justify-between px-6 border-b border-slate-800 shrink-0">
          <h1 className="text-white font-bold text-lg truncate" title={t(language, 'appTitle')}>
            {t(language, 'appTitle')}
          </h1>
          <button 
            className="md:hidden text-slate-400 hover:text-white transition-colors"
            onClick={() => setIsOpen(false)}
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        <nav className="flex-1 overflow-y-auto py-4">
          <ul className="space-y-1">
            {navItems.map((item) => {
              const Icon = item.icon;
              return (
                <li key={item.path}>
                  <NavLink
                    to={item.path}
                    onClick={() => setIsOpen(false)}
                    className={({ isActive }) =>
                      `flex items-center px-6 py-3 text-sm font-medium transition-colors ${
                        isActive
                          ? 'bg-brand-600 text-white'
                          : 'hover:bg-slate-800 hover:text-white'
                      }`
                    }
                  >
                    <Icon className="w-5 h-5 mr-3" />
                    {item.label}
                  </NavLink>
                </li>
              );
            })}
          </ul>
        </nav>

        {/* Bottom Navigation (Settings & Guide) */}
        <div className="mt-auto pb-2">
          <ul className="space-y-1">
            {bottomNavItems.map((item) => {
              const Icon = item.icon;
              return (
                <li key={item.path}>
                  <NavLink
                    to={item.path}
                    onClick={() => setIsOpen(false)}
                    className={({ isActive }) =>
                      `flex items-center px-6 py-3 text-sm font-medium transition-colors ${
                        isActive
                          ? 'bg-brand-600 text-white'
                          : 'hover:bg-slate-800 hover:text-white'
                      }`
                    }
                  >
                    <Icon className="w-5 h-5 mr-3" />
                    {item.label}
                  </NavLink>
                </li>
              );
            })}
          </ul>
        </div>

        {/* System Settings & Actions */}
        <div className="p-4 border-t border-slate-800 space-y-3">
          <button
            onClick={handleLogout}
            className="w-full flex items-center justify-center px-4 py-2.5 bg-slate-800 text-slate-300 hover:bg-slate-700 hover:text-white rounded-lg text-sm font-bold transition-colors shadow-sm"
          >
            <LogOut className="w-4 h-4 mr-2" />
            {t(language, 'logout')}
          </button>

          <button
            onClick={handleClearData}
            className="w-full flex items-center justify-center px-4 py-2 bg-red-500/10 text-red-400 hover:bg-red-500/20 rounded-lg text-sm font-medium transition-colors border border-red-500/20 mt-2"
          >
            <Trash2 className="w-4 h-4 mr-2" />
            Reset for Production
          </button>
          <div className="text-xs text-slate-500 text-center mt-2">
            ID: {restaurantId}
          </div>
        </div>
      </aside>

      {/* Modals */}
      {confirmModal && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all">
            <h3 className="text-lg font-bold text-gray-900 mb-2">ყურადღება / Warning</h3>
            <p className="text-sm text-gray-600 mb-6">{confirmModal.message}</p>
            <div className="flex space-x-3">
              <button onClick={() => setConfirmModal(null)} className="flex-1 px-4 py-2 border border-gray-300 text-gray-700 rounded-xl hover:bg-gray-50 font-medium">Cancel</button>
              <button onClick={() => { confirmModal.onConfirm(); setConfirmModal(null); }} className="flex-1 px-4 py-2 bg-red-600 text-white rounded-xl hover:bg-red-700 font-bold">Confirm</button>
            </div>
          </div>
        </div>
      )}

      {alertMessage && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-900/60 backdrop-blur-sm">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm p-6 transform transition-all text-center">
            <h3 className="text-lg font-bold text-gray-900 mb-2">შეტყობინება / Notification</h3>
            <p className="text-sm text-gray-600 mb-6">{alertMessage}</p>
            <button onClick={() => setAlertMessage(null)} className="w-full px-4 py-2 bg-brand-600 text-white rounded-xl hover:bg-brand-700 font-bold">OK</button>
          </div>
        </div>
      )}
    </>
  );
};
